import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [chatLog, setChatLog] = useState([]);

  const handleSendMessage = () => {
    if (message.length <= 50) {
      setChatLog([...chatLog, { text: message, from: 'user' }]);
      setMessage('');
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-full max-w-sm">
        <div className="flex justify-between items-center mb-4">
          <div className="flex items-center">
            <img src="https://via.placeholder.com/50" alt="Avatar" className="w-12 h-12 rounded-full"/>
            <span className="ml-2 text-lg font-bold">John Doe</span>
          </div>
          <div className="text-lg font-bold">Typing...</div>
        </div>
        <div className="bg-[#C06C88] p-4 rounded-lg">
          <textarea value={message} onChange={(e) => setMessage(e.target.value)} className="w-full h-12 p-2 text-lg text-white bg-[#B7D7CD] border-none focus:outline-none focus:ring-0"/>
        </div>
        <div className="flex justify-between items-center mt-4">
          <button className="bg-[#C06C88] p-2 text-lg text-white border-none rounded-lg hover:bg-[#B6C1C9]" onClick={handleSendMessage}>Send</button>
          <img src="https://via.placeholder.com/50" alt="Avatar" className="w-12 h-12 rounded-full"/>
        </div>
        <div className="overflow-y-auto h-64">
          {chatLog.map((log, index) => (
            <div key={index} className="bg-[#B7D7CD] p-4 mb-2">
              <span className="text-lg font-bold">{log.text}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
